-- Seed the prompt_bank table with the existing volunteer dashboard prompts.
-- Run backend/db/deploy_schema.sql first, then run this file.
-- This is additive/upsert-based and does not delete existing recordings or users.

on conflict (prompt_id, dialect) do update set
  module_id = excluded.module_id,
  module_title = excluded.module_title,
  prompt_type = excluded.prompt_type,
  english = excluded.english,
  transliteration = excluded.transliteration,
  difficulty = excluded.difficulty,
  curriculum_stage = excluded.curriculum_stage,
  grammatical_category = excluded.grammatical_category,
  weight = excluded.weight,
  active = excluded.active,
  sort_order = excluded.sort_order,
  updated_at = now();

